// TestUploadHandler_ContentSniffReject verifies the handler rejects uploads
// where the Content-Type header claims audio but the actual bytes are not audio.
func TestUploadHandler_ContentSniffReject(t *testing.T) {
	// Create a multipart request with Content-Type: audio/mpeg but PNG content
	var buf bytes.Buffer
	w := multipart.NewWriter(&buf)

	// CreateFormFile sets Content-Type to application/octet-stream by default,
	// so we create the part manually with an audio MIME type.
	partHeader := make(map[string][]string)
	partHeader["Content-Disposition"] = []string{`form-data; name="file"; filename="malicious.mp3"`}
	partHeader["Content-Type"] = []string{"audio/mpeg"}
	part, err := w.CreatePart(partHeader)
	if err != nil {
		t.Fatal(err)
	}

	// Write PNG magic bytes (not audio)
	pngHeader := append([]byte{0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A}, make([]byte, 100)...)
	if _, err := part.Write(pngHeader); err != nil {
		t.Fatal(err)
	}
	_ = w.Close()

	// We need a non-nil storage to get past the first check.
	// Use an empty storage.Client — the handler should reject before reaching S3.
	// storage.Client is a struct, so we pass a zero-value pointer.
	handler := uploadHandler(&emptyStorage, 50<<20)

	req := httptest.NewRequest(http.MethodPost, "/upload", &buf)
	req.Header.Set("Content-Type", w.FormDataContentType())
	ctx := auth.WithClaims(req.Context(), &auth.Claims{UserID: uuid.New()})
	req = req.WithContext(ctx)

	rr := httptest.NewRecorder()
	handler.ServeHTTP(rr, req)

	if rr.Code != http.StatusBadRequest {
		t.Errorf("expected 400 for spoofed audio, got %d: %s", rr.Code, rr.Body.String())
	}

	body := rr.Body.String()
	if !bytes.Contains([]byte(body), []byte("does not match")) {
		t.Errorf("expected content mismatch error, got: %s", body)
	}
}

// TestUploadHandler_FileTooSmall verifies the handler rejects files smaller
// than the minimum required for content sniffing.
func TestUploadHandler_FileTooSmall(t *testing.T) {
	var buf bytes.Buffer
	w := multipart.NewWriter(&buf)

	partHeader := make(map[string][]string)
	partHeader["Content-Disposition"] = []string{`form-data; name="file"; filename="tiny.mp3"`}
	partHeader["Content-Type"] = []string{"audio/mpeg"}
	part, err := w.CreatePart(partHeader)
	if err != nil {
		t.Fatal(err)
	}

	// Write only 4 bytes — too small for reliable sniffing
	if _, err := part.Write([]byte{0xFF, 0xFB, 0x90, 0x00}); err != nil {
		t.Fatal(err)
	}
	_ = w.Close()

	handler := uploadHandler(&emptyStorage, 50<<20)

	req := httptest.NewRequest(http.MethodPost, "/upload", &buf)
	req.Header.Set("Content-Type", w.FormDataContentType())
	ctx := auth.WithClaims(req.Context(), &auth.Claims{UserID: uuid.New()})
	req = req.WithContext(ctx)

	rr := httptest.NewRecorder()
	handler.ServeHTTP(rr, req)

	if rr.Code != http.StatusBadRequest {
		t.Errorf("expected 400 for tiny file, got %d: %s", rr.Code, rr.Body.String())
	}
}
